31	entity tb_asynchronous_fifo is
32	  generic (
33	    depth : positive;
34	    read_clock_is_faster : boolean;
35	    almost_empty_level : natural := 0;
36	    almost_full_level : natural := 0;
37	    read_stall_probability_percent : natural := 20;
38	    write_stall_probability_percent : natural := 20;
39	    enable_packet_mode : boolean := false;
40	    enable_last : boolean := false;
41	    enable_drop_packet : boolean := false;
42	    enable_output_register : boolean := false;
43	    runner_cfg : string
44	  );
45	end entity;
46	
47	architecture tb of tb_asynchronous_fifo is
48	
49	  -- Generic constants
50	  constant width : positive := 8;
51	
52	  -- DUT ports
53	  signal clk_read, clk_write : std_ulogic := '0';
54	
55	  signal write_ready, write_valid, write_last, write_almost_full : std_ulogic := '0';
56	  signal read_ready, read_valid, read_last, read_almost_empty : std_ulogic := '0';
57	  signal write_data, read_data : std_ulogic_vector(width - 1 downto 0) := (others => '0');
58	  signal write_level, read_level : natural range 0 to depth := 0;
59	
60	  signal drop_packet : std_ulogic := '0';
61	
62	  -- Testbench stuff
63	  constant read_stall_config : stall_configuration_t := (
64	    stall_probability => real(read_stall_probability_percent) / 100.0,
65	    min_stall_cycles => 1,
66	    max_stall_cycles => 4
67	  );
68	
69	  constant write_stall_config : stall_configuration_t := (
70	    stall_probability => real(write_stall_probability_percent) / 100.0,
71	    min_stall_cycles => 1,
72	    max_stall_cycles => 4
73	  );
74	
75	  constant write_queue, read_queue : queue_t := new_queue;
76	
77	  signal num_beats_written, num_packets_written, num_packets_read : natural := 0;
78	  signal has_gone_full_times, has_gone_empty_times : natural := 0;
79	
80	  signal enable_read : std_ulogic := '1';
81	
82	begin
83	
84	  test_runner_watchdog(runner, 2 ms);
85	
86	  clocks : if read_clock_is_faster generate
87	    clk_read <= not clk_read after 2 ns;
88	    clk_write <= not clk_write after 3 ns;
89	  else  generate
90	    clk_read <= not clk_read after 3 ns;
91	    clk_write <= not clk_write after 2 ns;
92	  end generate;
93	
94	
95	  ------------------------------------------------------------------------------
96	  main : process
97	
98	    variable rnd : RandomPType;
99	
100	    variable expected_num_packets_written, expected_num_packets_read : natural := 0;
101	
102	    procedure run_test(
103	      num_beats : natural;
104	      push_packet_to_checker_times : natural := 1
105	    ) is
106	      constant num_bytes : natural := num_beats * width / 8;
107	      variable data, data_copy : integer_array_t := null_integer_array;
108	    begin
109	      if num_beats > 0 then
110	        random_integer_array(
111	          rnd => rnd,
112	          integer_array => data,
113	          width => num_bytes,
114	          bits_per_word => 8,
115	          is_signed => false
116	        );
117	
118	        for packet_check_idx in 0 to push_packet_to_checker_times - 1 loop
119	          data_copy := copy(data);
120	          push_ref(read_queue, data_copy);
121	
122	          expected_num_packets_read := expected_num_packets_read + 1;
123	        end loop;
124	
125	        push_ref(write_queue, data);
126	
127	        expected_num_packets_written := expected_num_packets_written + 1;
128	      end if;
129	    end procedure;
130	
131	    procedure wait_until_write_done is
132	    begin
133	      wait until num_packets_written = expected_num_packets_written and rising_edge(clk_write);
134	    end procedure;
135	
136	    procedure wait_until_done is
137	    begin
138	      wait until num_packets_written = expected_num_packets_written
139	        and num_packets_read = expected_num_packets_read
140	        and rising_edge(clk_read);
141	    end procedure;
142	
143	    procedure wait_for_read_to_propagate is
144	    begin
145	      wait until rising_edge(clk_write);
146	      wait until rising_edge(clk_write);
147	      wait until rising_edge(clk_write);
148	      wait until rising_edge(clk_write);
149	    end procedure;
150	
151	    procedure wait_for_write_to_propagate is
152	    begin
153	      wait until rising_edge(clk_read);
154	      wait until rising_edge(clk_read);
155	      wait until rising_edge(clk_read);
156	      wait until rising_edge(clk_read);
157	
158	      if enable_output_register then
159	        wait until rising_edge(clk_read);
160	      end if;
161	    end procedure;
162	
163	    procedure pulse_drop_packet is
164	    begin
165	      drop_packet <= '1';
166	      wait until rising_edge(clk_write);
167	      drop_packet <= '0';
168	    end procedure;
169	
170	  begin
171	    test_runner_setup(runner, runner_cfg);
172	    rnd.InitSeed(get_string_seed(runner_cfg));
173	
174	    if run("test_init_state") then
175	      check_equal(read_valid, '0');
176	      check_equal(write_ready, '1');
177	      check_equal(write_almost_full, '0');
178	      check_equal(read_almost_empty, '1');
179	
180	      wait until
181	        read_valid'event
182	        or write_ready'event
183	        or write_almost_full'event
184	        or read_almost_empty'event
185	        for 1 us;
186	
187	      check_equal(read_valid, '0');
188	      check_equal(write_ready, '1');
189	      check_equal(write_almost_full, '0');
190	      check_equal(read_almost_empty, '1');
191	
192	    elsif run("test_write_faster_than_read") then
193	      for packet_idx in 0 to 1000 loop
194	        run_test(num_beats=>rnd.Uniform(1, 5));
195	      end loop;
196	
197	      wait_until_done;
198	      check_relation(has_gone_full_times > 200, "Got " & to_string(has_gone_full_times));
199	
200	    elsif run("test_read_faster_than_write") then
201	      for packet_idx in 0 to 1000 loop
202	        run_test(num_beats=>rnd.Uniform(1, 5));
203	      end loop;
204	
205	      wait_until_done;
206	      check_relation(has_gone_empty_times > 200, "Got " & to_string(has_gone_empty_times));
207	
208	    elsif run("test_packet_mode_random_data") then
209	      for packet_idx in 0 to 1000 loop
210	        run_test(num_beats=>rnd.Uniform(1, 5));
211	      end loop;
212	
213	    elsif run("test_packet_mode_status") then
214	      -- Start writing a packet and check status is the middle
215	      enable_read <= '0';
216	      run_test(num_beats=>depth - 1);
217	
218	      wait until num_beats_written = depth - 2 and rising_edge(clk_write);
219	      check_relation(write_level > 0);
220	      check_equal(read_valid, False);
221	
222	      -- Allow the test to finish
223	      enable_read <= '1';
224	
225	    elsif run("test_packet_mode_deep") then
226	      -- Show that the FIFO can be filled with lasts
227	
228	      -- Fill the FIFO with lasts
229	      enable_read <= '0';
230	
231	      for beat_idx in 1 to depth loop
232	        run_test(num_beats=>1);
233	      end loop;
234	      wait_until_write_done;
235	
236	      enable_read <= '1';
237	      wait until read_ready and read_valid and rising_edge(clk_read);
238	      enable_read <= '0';
239	
240	      run_test(num_beats=>1);
241	      wait_until_write_done;
242	
243	      enable_read <= '1';
244	      wait_until_done;
245	
246	      -- Fill the FIFO with lasts again
247	      enable_read <= '0';
248	      for i in 1 to depth loop
249	        run_test(num_beats=>1);
250	      end loop;
251	      wait_until_write_done;
252	
253	      enable_read <= '1';
254	      wait_until_done;
255	
256	      wait until rising_edge(clk_read);
257	      check_equal(read_valid, '0');
258	
259	    elsif run("test_drop_packet_mode_read_level_should_be_zero") then
260	      run_test(num_beats=>4);
261	      wait_until_write_done;
262	      wait_for_write_to_propagate;
263	
264	      check_equal(read_level, 0);
265	
266	    elsif run("test_drop_packet_random_data") then
267	      -- Write and read some data, to make the pointers advance a little.
268	      run_test(num_beats=>depth * 3 / 4);
269	      -- Write another packet, which we will drop so it is not pushed to checker.
270	      -- Note that the length chosen will make the write pointer wraparound.
271	      run_test(num_beats=>depth / 2, push_packet_to_checker_times=>0);
272	
273	      -- Wait until the first packet is fully written
274	      wait until write_ready and write_valid and write_last and rising_edge(clk_write);
275	      wait until rising_edge(clk_write);
276	      -- Set drop_packet on the very last beat of the second packet.
277	      -- The whole second packet should be dropped.
278	      wait until write_ready and write_valid and write_last;
279	      pulse_drop_packet;
280	
281	      -- Write and verify a clean packet. Should be the only thing remaining in the FIFO.
282	      wait_until_done;
283	      enable_read <= '0';
284	      run_test(num_beats=>4);
285	      wait_until_write_done;
286	
287	      if enable_output_register then
288	        -- With output register enabled, write level is pessimistic when there is nothing currently
289	        -- in the output register.
290	        check_equal(write_level, 5);
291	        -- When output register is enabled, it is a long roundtrip before the actual level value
292	        -- gets presented on the write side.
293	        -- The write address is resynced to read domain, which triggers a read from RAM into output
294	        -- register, then the updated read address is resynced back to write domain, which then
295	        -- updates the level.
296	        wait_for_read_to_propagate;
297	        wait_for_write_to_propagate;
298	      end if;
299	      -- Level should be correct.
300	      check_equal(write_level, 4);
301	
302	      enable_read <= '1';
303	      wait_until_done;
304	      check_equal(read_valid, '0');
305	      wait_for_read_to_propagate;
306	      check_equal(write_level, to_int(enable_output_register));
307	
308	    elsif run("test_levels_full_range") then
309	      -- Check empty status
310	      -- If output register is used, write_level is always 1 as the lowest
311	      check_equal(write_level, to_int(enable_output_register));
312	      check_equal(read_level, 0);
313	
314	      -- Fill the FIFO
315	      enable_read <= '0';
316	      run_test(num_beats=>depth);
317	      wait_until_write_done;
318	
319	      -- Check full status. Must wait a while before all writes have propagated to read side.
320	      check_equal(write_level, depth);
321	      wait_for_write_to_propagate;
322	      check_equal(read_level, depth);
323	
324	      -- Empty the FIFO
325	      enable_read <= '1';
326	      wait_until_done;
327	
328	      -- Check empty status. Must wait a while before all reads have propagated to write side.
329	      check_equal(read_level, 0);
330	      wait_for_read_to_propagate;
331	      check_equal(write_level, to_int(enable_output_register));
332	
333	    elsif run("test_write_almost_full") then
334	      check_equal(write_almost_full, '0');
335	
336	      enable_read <= '0';
337	      run_test(num_beats=>almost_full_level - 1);
338	      wait_until_write_done;
339	      check_equal(write_almost_full, '0');
340	
341	      run_test(num_beats=>1);
342	      wait_until_write_done;
343	      check_equal(write_almost_full, '1');
344	
345	      enable_read <= '1';
346	      wait until read_ready and read_valid and rising_edge(clk_read);
347	      wait_for_read_to_propagate;
348	      check_equal(write_almost_full, '0');
349	
350	    elsif run("test_read_almost_empty") then
351	      check_equal(read_almost_empty, '1');
352	
353	      enable_read <= '0';
354	      run_test(num_beats=>almost_empty_level);
355	      wait_until_write_done;
356	      wait_for_write_to_propagate;
357	      wait_for_write_to_propagate;
358	      check_equal(read_almost_empty, '1');
359	
360	      run_test(num_beats=>1);
361	      wait_until_write_done;
362	      wait_for_write_to_propagate;
363	      check_equal(read_almost_empty, '0');
364	
365	      enable_read <= '1';
366	      wait until read_ready and read_valid and rising_edge(clk_read);
367	      wait until rising_edge(clk_read);
368	      check_equal(read_almost_empty, '1');
369	
370	    end if;
371	
372	    wait_until_done;
373	
374	    test_runner_cleanup(runner);
375	  end process;
376	
377	
378	  ------------------------------------------------------------------------------
379	  read_status_tracking : process
380	    variable read_transaction : std_ulogic := '0';
381	  begin
382	    wait until rising_edge(clk_read);
383	
384	    -- If there was a read transaction last clock cycle, and we now want to read but there is no
385	    -- data available.
386	    if read_transaction and read_ready and not read_valid then
387	      has_gone_empty_times <= has_gone_empty_times + 1;
388	    end if;
389	
390	    read_transaction := read_ready and read_valid;
391	  end process;
392	
393	
394	  ------------------------------------------------------------------------------
395	  write_status_tracking : process
396	    variable write_transaction : std_ulogic := '0';
397	  begin
398	    wait until rising_edge(clk_write);
399	
400	    num_beats_written <= num_beats_written + to_int(write_ready and write_valid);
401	
402	    -- If there was a write transaction last clock cycle, and we now want to write but the fifo
403	    -- is full.
404	    if write_transaction and write_valid and not write_ready then
405	      has_gone_full_times <= has_gone_full_times + 1;
406	    end if;
407	
408	    write_transaction := write_ready and write_valid;
409	  end process;
410	
411	
412	  ------------------------------------------------------------------------------
413	  axi_stream_master_inst : entity bfm.axi_stream_master
414	    generic map (
415	      data_width => write_data'length,
416	      data_queue => write_queue,
417	      stall_config => write_stall_config,
418	      logger_name_suffix => " - write"
419	    )
420	    port map (
421	      clk => clk_write,
422	      --
423	      ready => write_ready,
424	      valid => write_valid,
425	      last => write_last,
426	      data => write_data,
427	      --
428	      num_packets_sent => num_packets_written
429	    );
430	
431	
432	  ------------------------------------------------------------------------------
433	  axi_stream_slave_inst : entity bfm.axi_stream_slave
434	    generic map (
435	      data_width => read_data'length,
436	      reference_data_queue => read_queue,
437	      stall_config => read_stall_config,
438	      logger_name_suffix => " - read",
439	      disable_last_check => not enable_last
440	    )
441	    port map (
442	      clk => clk_read,
443	      --
444	      ready => read_ready,
445	      valid => read_valid,
446	      last => read_last,
447	      data => read_data,
448	      --
449	      num_packets_checked => num_packets_read,
450	      enable => enable_read
451	    );
452	
453	
454	  ------------------------------------------------------------------------------
455	  check_no_bubble_cycles_in_packet_mode : if enable_packet_mode or enable_drop_packet generate
456	    signal start_event, end_event, en : std_ulogic := '0';
457	  begin
458	    -- These inputs must be signals (not constants), so assign them here instead of the port
459	    -- map directly
460	    start_event <= read_valid and not read_last;
461	    end_event <= (read_ready and read_valid and read_last);
462	    en <= '1';
463	
464	    check_stable(
465	      clock=>clk_read,
466	      en=>en,
467	      -- Start check when valid arrives
468	      start_event=>read_valid,
469	      -- End check when last arrives
470	      end_event=>end_event,
471	      -- Assert that valid is always asserted until last arrives
472	      expr=>read_valid,
473	      msg=>"There was a bubble in read_valid!"
474	    );
475	  end generate;
476	
477	
478	  ------------------------------------------------------------------------------
479	  dut : entity work.asynchronous_fifo
480	    generic map (
481	      width => width,
482	      depth => depth,
483	      almost_full_level => almost_full_level,
484	      almost_empty_level => almost_empty_level,
485	      -- Enable packet mode when we test drop_packet
486	      -- This way, we don't need to include redundant information in the test name
487	      enable_packet_mode => enable_packet_mode or enable_drop_packet,
488	      enable_last => enable_last,
489	      enable_drop_packet => enable_drop_packet,
490	      enable_output_register => enable_output_register
491	    )
492	    port map (
493	      clk_write => clk_write,
494	      write_ready => write_ready,
495	      write_valid => write_valid,
496	      write_data => write_data,
497	      write_last => write_last,
498	      --
499	      write_level => write_level,
500	      write_almost_full => write_almost_full,
501	      --
502	      drop_packet => drop_packet,
503	      --
504	      clk_read => clk_read,
505	      read_ready => read_ready,
506	      read_valid => read_valid,
507	      read_data => read_data,
508	      read_last => read_last,
509	      --
510	      read_level => read_level,
511	      read_almost_empty => read_almost_empty
512	    );
513	
514	end architecture;
